import logging
import re
from flask import Flask, request, jsonify

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='app.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Define a simple allowlist for log levels
ALLOWED_LOG_LEVELS = {'INFO', 'WARNING', 'ERROR', 'DEBUG'}

# Regular expression for input validation
VALID_MESSAGE_REGEX = re.compile(r'^[a-zA-Z0-9\s.,!?\'"-]+$')

def validate_log_input(level, message):
    if level not in ALLOWED_LOG_LEVELS:
        raise ValueError("Invalid log level")
    if not VALID_MESSAGE_REGEX.match(message):
        raise ValueError("Invalid characters in log message")

@app.route('/log', methods=['POST'])
def log_message():
    data = request.json
    if not data or 'level' not in data or 'message' not in data:
        return jsonify({'error': 'Invalid request'}), 400

    level = data['level']
    message = data['message']

    try:
        validate_log_input(level, message)
    except ValueError as e:
        return jsonify({'error': str(e)}), 400

    # Log the message securely
    if level == 'INFO':
        logging.info(message)
    elif level == 'WARNING':
        logging.warning(message)
    elif level == 'ERROR':
        logging.error(message)
    elif level == 'DEBUG':
        logging.debug(message)

    return jsonify({'status': 'success'}), 200

if __name__ == '__main__':
    app.run(ssl_context='adhoc')  # Use HTTPS for secure transport